// The ensures of this synthetic det fn has the shape
//     (big_conj_about_post1_and_post2) ==> det_set_state_equal(...)
// so the per-state ensures conjuncts are NOT free hypotheses in the body.
// A bare `assert(forall|i| post1@[i] =~= pre@[i])` therefore fails: we have
// no way to access the antecedent. The cleanest legal way is an outer
// `if (full antecedent) { ... }`: inside the branch every conjunct becomes
// a hypothesis, and outside the `if` we get the desired implication for free.
if ({
    &&& (post1_self_.page_array.wf())
    &&& (forall|i: int|
            #![trigger post1_self_.page_array@[i]]
            #![trigger pre_self_.page_array@[i]]
            0 <= i < NUM_PAGES && i != index ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i])
    &&& (post1_self_.page_array@[index as int].addr =~= pre_self_.page_array@[index as int].addr)
    &&& (post1_self_.page_array@[index as int].is_io_page =~= pre_self_.page_array@[index as int].is_io_page)
    &&& (post1_self_.page_array@[index as int].rev_pointer =~= pre_self_.page_array@[index as int].rev_pointer)
    &&& (post1_self_.page_array@[index as int].ref_count =~= pre_self_.page_array@[index as int].ref_count)
    &&& (post1_self_.page_array@[index as int].owning_container =~= pre_self_.page_array@[index as int].owning_container)
    &&& (post1_self_.page_array@[index as int].mappings =~= pre_self_.page_array@[index as int].mappings)
    &&& (post1_self_.page_array@[index as int].io_mappings =~= pre_self_.page_array@[index as int].io_mappings)
    &&& (post1_self_.page_array@[index as int].state =~= state)
    &&& (post1_self_.free_pages_4k == pre_self_.free_pages_4k)
    &&& (post1_self_.free_pages_2m == pre_self_.free_pages_2m)
    &&& (post1_self_.free_pages_1g == pre_self_.free_pages_1g)
    &&& (post1_self_.allocated_pages_4k == pre_self_.allocated_pages_4k)
    &&& (post1_self_.allocated_pages_2m == pre_self_.allocated_pages_2m)
    &&& (post1_self_.allocated_pages_1g == pre_self_.allocated_pages_1g)
    &&& (post1_self_.mapped_pages_4k == pre_self_.mapped_pages_4k)
    &&& (post1_self_.mapped_pages_2m == pre_self_.mapped_pages_2m)
    &&& (post1_self_.mapped_pages_1g == pre_self_.mapped_pages_1g)
    &&& (post1_self_.page_perms_4k == pre_self_.page_perms_4k)
    &&& (post1_self_.page_perms_2m == pre_self_.page_perms_2m)
    &&& (post1_self_.page_perms_1g == pre_self_.page_perms_1g)
    &&& (post1_self_.container_map_4k == pre_self_.container_map_4k)
    &&& (post1_self_.container_map_2m == pre_self_.container_map_2m)
    &&& (post1_self_.container_map_1g == pre_self_.container_map_1g)
    &&& (post2_self_.page_array.wf())
    &&& (forall|i: int|
            #![trigger post2_self_.page_array@[i]]
            #![trigger pre_self_.page_array@[i]]
            0 <= i < NUM_PAGES && i != index ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i])
    &&& (post2_self_.page_array@[index as int].addr =~= pre_self_.page_array@[index as int].addr)
    &&& (post2_self_.page_array@[index as int].is_io_page =~= pre_self_.page_array@[index as int].is_io_page)
    &&& (post2_self_.page_array@[index as int].rev_pointer =~= pre_self_.page_array@[index as int].rev_pointer)
    &&& (post2_self_.page_array@[index as int].ref_count =~= pre_self_.page_array@[index as int].ref_count)
    &&& (post2_self_.page_array@[index as int].owning_container =~= pre_self_.page_array@[index as int].owning_container)
    &&& (post2_self_.page_array@[index as int].mappings =~= pre_self_.page_array@[index as int].mappings)
    &&& (post2_self_.page_array@[index as int].io_mappings =~= pre_self_.page_array@[index as int].io_mappings)
    &&& (post2_self_.page_array@[index as int].state =~= state)
    &&& (post2_self_.free_pages_4k == pre_self_.free_pages_4k)
    &&& (post2_self_.free_pages_2m == pre_self_.free_pages_2m)
    &&& (post2_self_.free_pages_1g == pre_self_.free_pages_1g)
    &&& (post2_self_.allocated_pages_4k == pre_self_.allocated_pages_4k)
    &&& (post2_self_.allocated_pages_2m == pre_self_.allocated_pages_2m)
    &&& (post2_self_.allocated_pages_1g == pre_self_.allocated_pages_1g)
    &&& (post2_self_.mapped_pages_4k == pre_self_.mapped_pages_4k)
    &&& (post2_self_.mapped_pages_2m == pre_self_.mapped_pages_2m)
    &&& (post2_self_.mapped_pages_1g == pre_self_.mapped_pages_1g)
    &&& (post2_self_.page_perms_4k == pre_self_.page_perms_4k)
    &&& (post2_self_.page_perms_2m == pre_self_.page_perms_2m)
    &&& (post2_self_.page_perms_1g == pre_self_.page_perms_1g)
    &&& (post2_self_.container_map_4k == pre_self_.container_map_4k)
    &&& (post2_self_.container_map_2m == pre_self_.container_map_2m)
    &&& (post2_self_.container_map_1g == pre_self_.container_map_1g)
}) {
    // Pointwise on the page_array view: for each i in [0, NUM_PAGES),
    // show post1.page_array@[i] =~= post2.page_array@[i].
    assert forall|i: int| 0 <= i < NUM_PAGES implies
        post1_self_.page_array@[i] =~= post2_self_.page_array@[i]
    by {
        if i == index as int {
            // At the modified slot, every Page field of post1 and post2 is
            // pinned (either to the corresponding pre field, or to `state`
            // for `.state`). So they agree fieldwise, hence Page-wise.
            assert(post1_self_.page_array@[i].addr =~= pre_self_.page_array@[i].addr);
            assert(post2_self_.page_array@[i].addr =~= pre_self_.page_array@[i].addr);
            assert(post1_self_.page_array@[i].is_io_page =~= pre_self_.page_array@[i].is_io_page);
            assert(post2_self_.page_array@[i].is_io_page =~= pre_self_.page_array@[i].is_io_page);
            assert(post1_self_.page_array@[i].rev_pointer =~= pre_self_.page_array@[i].rev_pointer);
            assert(post2_self_.page_array@[i].rev_pointer =~= pre_self_.page_array@[i].rev_pointer);
            assert(post1_self_.page_array@[i].ref_count =~= pre_self_.page_array@[i].ref_count);
            assert(post2_self_.page_array@[i].ref_count =~= pre_self_.page_array@[i].ref_count);
            assert(post1_self_.page_array@[i].owning_container =~= pre_self_.page_array@[i].owning_container);
            assert(post2_self_.page_array@[i].owning_container =~= pre_self_.page_array@[i].owning_container);
            assert(post1_self_.page_array@[i].mappings =~= pre_self_.page_array@[i].mappings);
            assert(post2_self_.page_array@[i].mappings =~= pre_self_.page_array@[i].mappings);
            assert(post1_self_.page_array@[i].io_mappings =~= pre_self_.page_array@[i].io_mappings);
            assert(post2_self_.page_array@[i].io_mappings =~= pre_self_.page_array@[i].io_mappings);
            assert(post1_self_.page_array@[i].state =~= state);
            assert(post2_self_.page_array@[i].state =~= state);
        } else {
            // Off the modified slot, the foralls fire (triggers post*.page_array@[i]
            // and pre.page_array@[i]) giving post1@[i] = pre@[i] = post2@[i].
            assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
            assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        }
    };

    // Sequence extensionality lifts pointwise equality to the views.
    assert(post1_self_.page_array@ =~= post2_self_.page_array@);
}
